            {PERSONAL_INFO.name}
          </h1>
          <h2 className="text-2xl md:text-4xl font-semibold text-slate-400">
            {PERSONAL_INFO.role} & <span className="gradient-text">Aspiring Software Engineer</span>
          </h2>
