          <p className={`max-w-xl text-lg leading-relaxed mt-6 transition-colors ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>
            Currently pursuing B.E at {EDUCATION[0].institute}. I build high-performance, accessible, and interactive web applications.
          </p>
          <div className="flex flex-wrap gap-4 mt-10">
            <a href="#projects" className="bg-indigo-600 hover:bg-indigo-700 text-white px-8 py-3 rounded-lg font-semibold transition-all flex items-center gap-2 shadow-lg shadow-indigo-600/20">
              View Work <ChevronRight size={18} />
