            <a href="#contact" className={`glass hover:scale-105 px-8 py-3 rounded-lg font-semibold transition-all ${isDarkMode ? 'text-white' : 'text-slate-900 border-slate-200 shadow-sm'}`}>
              Contact Me
            </a>
          </div>
        </div>
      </section>

      {/* About Section */}
      <section id="about" className={`py-24 px-6 transition-colors duration-300 ${isDarkMode ? 'bg-slate-900/50' : 'bg-slate-100/50'}`}>
