                    {isSubmitting ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : <>Send Message <Send size={18} /></>}
                  </button>
                </form>
              )}
            </div>
          </div>
        </div>
      </section>

      <Assistant />
    </Layout>
  );
};

