import React, { useState, useEffect, useRef } from 'react';
import Layout from './components/Layout';
import Assistant from './components/Assistant';
import { 
  Mail, 
  Phone, 
  MapPin, 
  Code, 
  Briefcase, 
  GraduationCap, 
  Github, 
  ExternalLink,
  ChevronRight,
  Database,
  Send,
  CheckCircle,
  AlertCircle,
  Download
} from 'lucide-react';
import { PERSONAL_INFO, SKILLS, EDUCATION, EXPERIENCE, PROJECTS } from './constants';

interface FormData {
  name: string;
  email: string;
  subject: string;
  message: string;
}

interface FormErrors {
  name?: string;
  email?: string;
  subject?: string;
  message?: string;
}

const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem('portfolio-theme');
    return saved ? saved === 'dark' : true;
  });

  const [formData, setFormData] = useState<FormData>({
    name: '',
    email: '',
    subject: '',
    message: ''
  });

  const [errors, setErrors] = useState<FormErrors>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);

  // Animation states
  const [skillsVisible, setSkillsVisible] = useState(false);
  const [projectsVisible, setProjectsVisible] = useState(false);

  const skillsRef = useRef<HTMLDivElement>(null);
  const projectsRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    localStorage.setItem('portfolio-theme', isDarkMode ? 'dark' : 'light');
    document.documentElement.className = isDarkMode ? 'theme-dark' : 'theme-light';
  }, [isDarkMode]);

  useEffect(() => {
    const createObserver = (setVisible: React.Dispatch<React.SetStateAction<boolean>>) => 
      new IntersectionObserver(
        ([entry]) => {
          if (entry.isIntersecting) {
            setVisible(true);
          }
        },
        { threshold: 0.1 }
      );

    const sObserver = createObserver(setSkillsVisible);
    if (skillsRef.current) sObserver.observe(skillsRef.current);

    const pObserver = createObserver(setProjectsVisible);
    if (projectsRef.current) pObserver.observe(projectsRef.current);

    return () => {
      sObserver.disconnect();
      pObserver.disconnect();
    };
  }, []);

  const toggleTheme = () => setIsDarkMode(prev => !prev);

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    if (!formData.name.trim()) newErrors.name = "Name is required";
    if (!formData.email.trim()) newErrors.email = "Email is required";
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) newErrors.email = "Invalid email";
    if (!formData.subject.trim()) newErrors.subject = "Subject is required";
    if (!formData.message.trim()) newErrors.message = "Message is required";
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;
    setIsSubmitting(true);
    await new Promise(resolve => setTimeout(resolve, 1500));
    setIsSubmitting(false);
    setIsSubmitted(true);
    setFormData({ name: '', email: '', subject: '', message: '' });
    setTimeout(() => setIsSubmitted(false), 5000);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    if (errors[name as keyof FormErrors]) {
      setErrors(prev => ({ ...prev, [name]: undefined }));
    }
  };

  return (
    <Layout isDarkMode={isDarkMode} toggleTheme={toggleTheme}>
      {/* Hero Section */}
      <section id="home" className="min-h-[80vh] flex flex-col justify-center px-6 max-w-6xl mx-auto py-20">
        <div className="space-y-4">
          <span className="text-indigo-400 font-mono tracking-widest text-sm uppercase block">Hello, I'm</span>
          <h1 className={`text-5xl md:text-7xl font-bold tracking-tight leading-tight transition-colors ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>
            {PERSONAL_INFO.name}
          </h1>
          <h2 className={`text-2xl md:text-4xl font-semibold transition-colors ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>
            {PERSONAL_INFO.role} & <span className="gradient-text">Aspiring Software Engineer</span>
          </h2>
          <p className={`max-w-xl text-lg leading-relaxed mt-6 transition-colors ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>
            Currently pursuing B.E at {EDUCATION[0].institute}. I build high-performance, accessible, and interactive web applications.
          </p>
