export default App;

import React, { useState, useEffect, useRef } from 'react';
import Layout from './components/Layout';
import Assistant from './components/Assistant';
import { 
  Mail, 
  Phone, 
  MapPin, 
  Code, 
  Briefcase, 
  GraduationCap, 
  Github, 
  ExternalLink,
  ChevronRight,
  Database,
  Send, 
  CheckCircle,
  AlertCircle,
  Download
} from 'lucide-react';
import { PERSONAL_INFO, SKILLS, EDUCATION, EXPERIENCE, PROJECTS } from './constants';

interface FormData {
  name: string;
  email: string;
  subject: string;
  message: string;
}

interface FormErrors {
  name?: string;
  email?: string;
  subject?: string;
  message?: string;
}

const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem('portfolio-theme');
    return saved ? saved === 'dark' : true;
  });

  const [formData, setFormData] = useState<FormData>({
    name: '',
    email: '',
    subject: '',
    message: ''
  });

  const [errors, setErrors] = useState<FormErrors>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);

  // Animation states
  const [heroVisible, setHeroVisible] = useState(false);
  const [aboutVisible, setAboutVisible] = useState(false);
  const [experienceVisible, setExperienceVisible] = useState(false);
  const [educationVisible, setEducationVisible] = useState(false);
  const [skillsVisible, setSkillsVisible] = useState(false);
  const [projectsVisible, setProjectsVisible] = useState(false);
  const [contactVisible, setContactVisible] = useState(false);

  const heroRef = useRef<HTMLDivElement>(null);
  const aboutRef = useRef<HTMLDivElement>(null);
  const experienceRef = useRef<HTMLDivElement>(null);
  const educationRef = useRef<HTMLDivElement>(null);
  const skillsRef = useRef<HTMLDivElement>(null);
  const projectsRef = useRef<HTMLDivElement>(null);
  const contactRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    localStorage.setItem('portfolio-theme', isDarkMode ? 'dark' : 'light');
    document.documentElement.className = isDarkMode ? 'theme-dark' : 'theme-light';
  }, [isDarkMode]);

  useEffect(() => {
    const createObserver = (setVisible: React.Dispatch<React.SetStateAction<boolean>>) => 
      new IntersectionObserver(
        ([entry]) => {
          if (entry.isIntersecting) {
            setVisible(true);
          }
        },
        { threshold: 0.1 }
      );

    const observers = [
      { ref: heroRef, setter: setHeroVisible },
      { ref: aboutRef, setter: setAboutVisible },
      { ref: experienceRef, setter: setExperienceVisible },
      { ref: educationRef, setter: setEducationVisible },
      { ref: skillsRef, setter: setSkillsVisible },
      { ref: projectsRef, setter: setProjectsVisible },
      { ref: contactRef, setter: setContactVisible },
    ].map(obs => {
      const observer = createObserver(obs.setter);
      if (obs.ref.current) observer.observe(obs.ref.current);
      return observer;
    });

    return () => {
      observers.forEach(o => o.disconnect());
    };
  }, []);

  const toggleTheme = () => setIsDarkMode(prev => !prev);

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    if (!formData.name.trim()) newErrors.name = "Name is required";
    if (!formData.email.trim()) newErrors.email = "Email is required";
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) newErrors.email = "Invalid email";
    if (!formData.subject.trim()) newErrors.subject = "Subject is required";
    if (!formData.message.trim()) newErrors.message = "Message is required";
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;
    setIsSubmitting(true);
    await new Promise(resolve => setTimeout(resolve, 1500));
    setIsSubmitting(false);
    setIsSubmitted(true);
    setFormData({ name: '', email: '', subject: '', message: '' });
    setTimeout(() => setIsSubmitted(false), 5000);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    if (errors[name as keyof FormErrors]) {
      setErrors(prev => ({ ...prev, [name]: undefined }));
    }
  };

  const animClasses = (visible: boolean) => 
    `transition-all duration-1000 ease-out transform ${visible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-12'}`;

  return (
    <Layout isDarkMode={isDarkMode} toggleTheme={toggleTheme}>
      {/* Hero Section */}
      <section id="home" className="min-h-[80vh] flex flex-col justify-center px-6 max-w-6xl mx-auto py-20" ref={heroRef}>
        <div className={`space-y-4 ${animClasses(heroVisible)}`}>
          <span className="text-indigo-400 font-mono tracking-widest text-sm uppercase block">Hello, I'm</span>
          <h1 className={`text-5xl md:text-7xl font-bold tracking-tight leading-tight transition-colors ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>
            {PERSONAL_INFO.name}
          </h1>
          <h2 className={`text-2xl md:text-4xl font-semibold transition-colors ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>
            {PERSONAL_INFO.role} & <span className="gradient-text">Aspiring Software Engineer</span>
          </h2>
          <p className={`max-w-xl text-lg leading-relaxed mt-6 transition-colors ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>
            Currently pursuing B.E at {EDUCATION[0].institute}. I build high-performance, accessible, and interactive web applications.
          </p>
          <div className="flex flex-wrap gap-4 mt-10">
            <a href="#projects" className="bg-indigo-600 hover:bg-indigo-700 text-white px-8 py-3 rounded-lg font-semibold transition-all flex items-center gap-2 shadow-lg shadow-indigo-600/20">
              View Work <ChevronRight size={18} />
            </a>
            <a href="#contact" className={`glass hover:scale-105 px-8 py-3 rounded-lg font-semibold transition-all ${isDarkMode ? 'text-white' : 'text-slate-900 border-slate-200 shadow-sm'}`}>
              Contact Me
            </a>
            <a 
              href="#" 
              download="Het_Maniya_Resume.pdf"
              className={`flex items-center gap-2 px-8 py-3 rounded-lg font-semibold transition-all border ${isDarkMode ? 'bg-indigo-600/10 border-indigo-500/30 text-indigo-400 hover:bg-indigo-600/20' : 'bg-slate-200 border-slate-300 text-slate-800 hover:bg-slate-300'}`}
            >
              <Download size={18} /> Resume
            </a>
          </div>
        </div>
      </section>

      {/* About Section */}
      <section id="about" className={`py-24 px-6 transition-colors duration-300 ${isDarkMode ? 'bg-slate-900/50' : 'bg-slate-100/50'}`} ref={aboutRef}>
        <div className={`max-w-6xl mx-auto grid md:grid-cols-2 gap-12 items-center ${animClasses(aboutVisible)}`}>
          <div className="relative group">
            <div className={`absolute -inset-4 bg-gradient-to-r from-indigo-500 to-purple-500 rounded-2xl opacity-20 group-hover:opacity-40 transition-opacity blur-2xl`}></div>
            <div className={`relative aspect-square rounded-2xl overflow-hidden glass ${isDarkMode ? 'border-white/10' : 'border-slate-200'}`}>
