const Contact = ({ isDarkMode }: { isDarkMode: boolean }) => {
  const [formData, setFormData] = useState({ name: '', email: '', subject: '', message: '' });
  const [errors, setErrors] = useState<any>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);

  const validate = (): boolean => {
    const newErrors: any = {};
    if (!formData.name.trim()) newErrors.name = "Name is required";
    if (!formData.email.trim()) newErrors.email = "Email is required";
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) newErrors.email = "Invalid email";
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;
    setIsSubmitting(true);
    await new Promise(resolve => setTimeout(resolve, 1500));
    setIsSubmitting(false);
    setIsSubmitted(true);
    setFormData({ name: '', email: '', subject: '', message: '' });
    setTimeout(() => setIsSubmitted(false), 5000);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  return (
    <section className="py-24 px-6 max-w-4xl mx-auto">
      <div className="text-center mb-12">
        <h3 className={`text-4xl font-bold mb-4 transition-colors ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>Let's build something great.</h3>
        <p className={`text-lg max-w-xl mx-auto transition-colors ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>
          Ready to start a project? Send me a message and I'll get back to you as soon as possible.
        </p>
      </div>

      <div className="grid md:grid-cols-5 gap-12 items-start">
        <div className="md:col-span-2 space-y-8">
          <div className={`glass p-8 rounded-2xl space-y-6 ${isDarkMode ? 'border-white/10' : 'border-slate-200 bg-white shadow-lg'}`}>
            {[
              { icon: <Mail size={24}/>, title: "Email", value: PERSONAL_INFO.email, color: 'text-indigo-400' },
              { icon: <Phone size={24}/>, title: "Phone", value: PERSONAL_INFO.phone, color: 'text-purple-400' },
              { icon: <MapPin size={24}/>, title: "Location", value: PERSONAL_INFO.location, color: 'text-blue-400' }
            ].map((item, idx) => (
              <div key={idx} className="flex items-start gap-4">
                <div className={`w-12 h-12 rounded-xl flex items-center justify-center shrink-0 ${isDarkMode ? 'bg-slate-800' : 'bg-slate-100'} ${item.color}`}>
                  {item.icon}
                </div>
                <div>
                  <h4 className={`font-semibold transition-colors ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>{item.title}</h4>
                  <p className={`text-sm transition-colors ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>{item.value}</p>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="md:col-span-3">
          <div className={`glass p-8 rounded-3xl relative overflow-hidden ${isDarkMode ? 'border-white/10' : 'border-slate-200 shadow-xl bg-white'}`}>
            {isSubmitted ? (
              <div className="py-12 flex flex-col items-center text-center space-y-4 animate-in fade-in zoom-in duration-300">
                <CheckCircle size={48} className="text-green-500 mb-2" />
                <h4 className={`text-2xl font-bold ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>Message Sent!</h4>
                <p className="text-slate-400">I'll get back to you shortly!</p>
                <button onClick={() => setIsSubmitted(false)} className="mt-6 text-indigo-400 font-semibold hover:underline">Send another</button>
              </div>
            ) : (
              <form onSubmit={handleSubmit} className="space-y-6">
                <div className="grid sm:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-xs font-bold uppercase tracking-widest text-slate-400 ml-1">Full Name</label>
                    <input 
                      type="text" name="name" value={formData.name} onChange={handleChange} placeholder="John Doe"
                      className={`w-full border rounded-xl px-4 py-3 focus:outline-none focus:ring-4 transition-all ${isDarkMode ? 'bg-slate-800/50 border-white/5 text-white focus:ring-indigo-500/20' : 'bg-slate-50 border-slate-200 text-slate-900 focus:ring-indigo-500/20'}`}
                    />
                    {errors.name && <p className="text-red-400 text-[10px] flex items-center gap-1 mt-1 uppercase font-bold tracking-tighter"><AlertCircle size={10} /> {errors.name}</p>}
                  </div>
                  <div className="space-y-2">
                    <label className="text-xs font-bold uppercase tracking-widest text-slate-400 ml-1">Email</label>
                    <input 
                      type="email" name="email" value={formData.email} onChange={handleChange} placeholder="john@example.com"
                      className={`w-full border rounded-xl px-4 py-3 focus:outline-none focus:ring-4 transition-all ${isDarkMode ? 'bg-slate-800/50 border-white/5 text-white focus:ring-indigo-500/20' : 'bg-slate-50 border-slate-200 text-slate-900 focus:ring-indigo-500/20'}`}
                    />
                    {errors.email && <p className="text-red-400 text-[10px] flex items-center gap-1 mt-1 uppercase font-bold tracking-tighter"><AlertCircle size={10} /> {errors.email}</p>}
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-bold uppercase tracking-widest text-slate-400 ml-1">Subject</label>
                  <input 
                    type="text" name="subject" value={formData.subject} onChange={handleChange} placeholder="Project Inquiry"
                    className={`w-full border rounded-xl px-4 py-3 focus:outline-none focus:ring-4 transition-all ${isDarkMode ? 'bg-slate-800/50 border-white/5 text-white focus:ring-indigo-500/20' : 'bg-slate-50 border-slate-200 text-slate-900 focus:ring-indigo-500/20'}`}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-bold uppercase tracking-widest text-slate-400 ml-1">Message</label>
                  <textarea 
                    name="message" value={formData.message} onChange={handleChange} rows={4} placeholder="Hello..."
                    className={`w-full border rounded-xl px-4 py-3 focus:outline-none focus:ring-4 transition-all resize-none ${isDarkMode ? 'bg-slate-800/50 border-white/5 text-white focus:ring-indigo-500/20' : 'bg-slate-50 border-slate-200 text-slate-900 focus:ring-indigo-500/20'}`}
                  ></textarea>
                </div>
                <button type="submit" disabled={isSubmitting} className="w-full bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-8 py-4 rounded-xl font-bold transition-all flex items-center justify-center gap-3 shadow-xl shadow-indigo-600/20">
                  {isSubmitting ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : <>Send Message <Send size={18} /></>}
                </button>
              </form>
            )}
          </div>
        </div>
      </div>
    </section>
  );
};

