const Contact = ({ isDarkMode }: { isDarkMode: boolean }) => {
  const [formData, setFormData] = useState({ name: '', email: '', subject: '', message: '' });
  const [errors, setErrors] = useState<any>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);

  const validate = (): boolean => {
    const newErrors: any = {};
    if (!formData.name.trim()) newErrors.name = "Name is required";
    if (!formData.email.trim()) newErrors.email = "Email is required";
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) newErrors.email = "Invalid email";
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;
    setIsSubmitting(true);
    await new Promise(resolve => setTimeout(resolve, 1500));
    setIsSubmitting(false);
    setIsSubmitted(true);
    setFormData({ name: '', email: '', subject: '', message: '' });
    setTimeout(() => setIsSubmitted(false), 5000);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  return (
    <section className="py-24 px-6 max-w-6xl mx-auto">
      <PageHeader 
        title="Get In Touch" 
        subtitle="Have a project in mind? Let's discuss how we can work together." 
        isDarkMode={isDarkMode} 
      />
      <div className="grid lg:grid-cols-5 gap-16 items-start">
        <div className="lg:col-span-2 space-y-8">
          <div className={`glass p-10 rounded-3xl space-y-8 ${isDarkMode ? 'bg-slate-800/50' : 'bg-white shadow-xl'}`}>
            {[
              { icon: <Mail size={24}/>, title: "Email Address", value: PERSONAL_INFO.email, color: 'text-indigo-400' },
              { icon: <Phone size={24}/>, title: "Phone Number", value: PERSONAL_INFO.phone, color: 'text-purple-400' },
              { icon: <MapPin size={24}/>, title: "Home Office", value: PERSONAL_INFO.address, color: 'text-blue-400' }
            ].map((item, idx) => (
              <div key={idx} className="flex items-start gap-6">
                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shrink-0 ${isDarkMode ? 'bg-slate-900 shadow-inner' : 'bg-slate-50 shadow-sm'} ${item.color}`}>
                  {item.icon}
                </div>
                <div>
                  <h4 className={`font-bold text-lg mb-1 ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>{item.title}</h4>
                  <p className={`text-sm leading-relaxed ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>{item.value}</p>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="lg:col-span-3">
          <div className={`glass p-10 rounded-3xl relative overflow-hidden ${isDarkMode ? 'bg-slate-800/50' : 'bg-white shadow-xl'}`}>
            {isSubmitted ? (
              <div className="py-20 flex flex-col items-center text-center space-y-4 animate-in fade-in zoom-in duration-500">
                <div className="w-20 h-20 rounded-full bg-green-500/20 text-green-500 flex items-center justify-center mb-4">
                  <CheckCircle size={40} />
                </div>
                <h4 className={`text-3xl font-black ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>Success!</h4>
                <p className="text-slate-400 max-w-xs">Your message has been received. I'll get back to you within 24 hours.</p>
                <button onClick={() => setIsSubmitted(false)} className="mt-8 text-indigo-400 font-black uppercase tracking-widest hover:underline text-sm">Send another message</button>
              </div>
            ) : (
              <form onSubmit={handleSubmit} className="space-y-8">
                <div className="grid sm:grid-cols-2 gap-8">
                  <div className="space-y-3">
                    <label className="text-xs font-black uppercase tracking-[0.2em] text-slate-500 ml-1">Full Name</label>
                    <input 
                      type="text" name="name" value={formData.name} onChange={handleChange} placeholder="What should I call you?"
                      className={`w-full border-2 rounded-2xl px-5 py-4 focus:outline-none focus:ring-4 transition-all ${isDarkMode ? 'bg-slate-900 border-white/5 text-white focus:ring-indigo-500/20' : 'bg-slate-50 border-slate-200 text-slate-900 focus:ring-indigo-500/20'}`}
                    />
                    {errors.name && <p className="text-red-400 text-[10px] flex items-center gap-1 mt-1 uppercase font-bold"><AlertCircle size={10} /> {errors.name}</p>}
                  </div>
                  <div className="space-y-3">
                    <label className="text-xs font-black uppercase tracking-[0.2em] text-slate-500 ml-1">Email Address</label>
                    <input 
                      type="email" name="email" value={formData.email} onChange={handleChange} placeholder="Where can I reach you?"
                      className={`w-full border-2 rounded-2xl px-5 py-4 focus:outline-none focus:ring-4 transition-all ${isDarkMode ? 'bg-slate-900 border-white/5 text-white focus:ring-indigo-500/20' : 'bg-slate-50 border-slate-200 text-slate-900 focus:ring-indigo-500/20'}`}
                    />
                    {errors.email && <p className="text-red-400 text-[10px] flex items-center gap-1 mt-1 uppercase font-bold"><AlertCircle size={10} /> {errors.email}</p>}
                  </div>
                </div>
                <div className="space-y-3">
                  <label className="text-xs font-black uppercase tracking-[0.2em] text-slate-500 ml-1">Subject</label>
                  <input 
                    type="text" name="subject" value={formData.subject} onChange={handleChange} placeholder="How can I help you today?"
                    className={`w-full border-2 rounded-2xl px-5 py-4 focus:outline-none focus:ring-4 transition-all ${isDarkMode ? 'bg-slate-900 border-white/5 text-white focus:ring-indigo-500/20' : 'bg-slate-50 border-slate-200 text-slate-900 focus:ring-indigo-500/20'}`}
                  />
                </div>
                <div className="space-y-3">
                  <label className="text-xs font-black uppercase tracking-[0.2em] text-slate-500 ml-1">Your Message</label>
                  <textarea 
                    name="message" value={formData.message} onChange={handleChange} rows={5} placeholder="Tell me about your project or inquiry..."
                    className={`w-full border-2 rounded-2xl px-5 py-4 focus:outline-none focus:ring-4 transition-all resize-none ${isDarkMode ? 'bg-slate-900 border-white/5 text-white focus:ring-indigo-500/20' : 'bg-slate-50 border-slate-200 text-slate-900 focus:ring-indigo-500/20'}`}
                  ></textarea>
                </div>
                <button type="submit" disabled={isSubmitting} className="w-full bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-8 py-5 rounded-2xl font-black uppercase tracking-widest transition-all flex items-center justify-center gap-3 shadow-2xl shadow-indigo-600/30 active:scale-[0.98]">
                  {isSubmitting ? <div className="w-6 h-6 border-4 border-white/30 border-t-white rounded-full animate-spin"></div> : <>Send Message <Send size={20} /></>}
                </button>
              </form>
            )}
          </div>
        </div>
      </div>
    </section>
  );
};

