const Contact = ({ isDarkMode }: { isDarkMode: boolean }) => {
  const [formData, setFormData] = useState({ name: '', email: '', subject: '', message: '' });
  const [errors, setErrors] = useState<any>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);

  const validate = (): boolean => {
    const newErrors: any = {};
    if (!formData.name.trim()) newErrors.name = "Name is required";
    if (!formData.email.trim()) newErrors.email = "Email is required";
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) newErrors.email = "Invalid email";
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;
    setIsSubmitting(true);
    await new Promise(resolve => setTimeout(resolve, 1500));
    setIsSubmitting(false);
    setIsSubmitted(true);
    setFormData({ name: '', email: '', subject: '', message: '' });
    setTimeout(() => setIsSubmitted(false), 5000);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  return (
    <section className="py-24 px-6 max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-8 duration-700">
      <div className="text-center mb-12">
        <h3 className={`text-4xl font-bold mb-4 transition-colors ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>Let's build something great.</h3>
        <p className={`text-lg max-w-xl mx-auto transition-colors ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>
          Ready to start a project? Send me a message and I'll get back to you as soon as possible.
        </p>
      </div>

      <div className="grid md:grid-cols-5 gap-12 items-start">
        <div className="md:col-span-2 space-y-8">
          <div className={`glass p-8 rounded-2xl space-y-6 ${isDarkMode ? 'border-white/10' : 'border-slate-200 bg-white shadow-lg'}`}>
            {[
              { icon: <Mail size={24}/>, title: "Email", value: PERSONAL_INFO.email, color: 'text-indigo-400' },
              { icon: <Phone size={24}/>, title: "Phone", value: PERSONAL_INFO.phone, color: 'text-purple-400' },
              { icon: <MapPin size={24}/>, title: "Location", value: PERSONAL_INFO.location, color: 'text-blue-400' }
            ].map((item, idx) => (
              <div key={idx} className="flex items-start gap-4">
                <div className={`w-12 h-12 rounded-xl flex items-center justify-center shrink-0 ${isDarkMode ? 'bg-slate-800' : 'bg-slate-100'} ${item.color}`}>
                  {item.icon}
                </div>
                <div>
                  <h4 className={`font-semibold transition-colors ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>{item.title}</h4>
                  <p className={`text-sm transition-colors ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>{item.value}</p>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="md:col-span-3">
          <div className={`glass p-8 rounded-3xl relative overflow-hidden ${isDarkMode ? 'border-white/10' : 'border-slate-200 shadow-xl bg-white'}`}>
            {isSubmitted ? (
              <div className="py-12 flex flex-col items-center text-center space-y-4 animate-in fade-in zoom-in duration-300">
                <CheckCircle size={48} className="text-green-500 mb-2" />
                <h4 className={`text-2xl font-bold ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>Message Sent!</h4>
                <p className="text-slate-400">I'll get back to you shortly!</p>
                <button onClick={() => setIsSubmitted(false)} className="mt-6 text-indigo-400 font-semibold hover:underline">Send another</button>
