// Added React.FC type definition to handle built-in React props like 'key' correctly during list rendering.
const ProjectCard: React.FC<{ project: Project, isDarkMode: boolean }> = ({ project, isDarkMode }) => {
  const [isVisible, setIsVisible] = useState(false);
  const cardRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
          observer.unobserve(entry.target);
        }
      },
      { 
        threshold: 0.15,
        rootMargin: '0px 0px -50px 0px'
      }
    );

    if (cardRef.current) {
      observer.observe(cardRef.current);
    }

    return () => observer.disconnect();
  }, []);

  return (
    <div 
      ref={cardRef}
      className={`group glass rounded-[2.5rem] overflow-hidden flex flex-col transition-all duration-1000 transform ${
        isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-20'
      } ${isDarkMode ? 'border-white/5 hover:border-indigo-500/30' : 'border-slate-200 hover:border-indigo-300'}`}
    >
      <div className="h-64 bg-slate-800 overflow-hidden relative">
        <img 
          src={project.imageUrl} 
          alt={project.title} 
