// --- Animated Project Card Component ---
const ProjectCard: React.FC<{ project: Project, isDarkMode: boolean }> = ({ project, isDarkMode }) => {
  const [isVisible, setIsVisible] = useState(false);
  const cardRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
          observer.unobserve(entry.target);
        }
      },
      { 
        threshold: 0.15,
        rootMargin: '0px 0px -50px 0px'
      }
    );

    if (cardRef.current) {
      observer.observe(cardRef.current);
    }

    return () => observer.disconnect();
  }, []);

  return (
    <div 
      ref={cardRef}
      className={`group glass rounded-[2.5rem] overflow-hidden flex flex-col transition-all duration-500 transform ${
        isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-20'
      } hover:-translate-y-3 hover:shadow-[0_20px_50px_rgba(99,102,241,0.15)] ${
        isDarkMode 
          ? 'border-white/5 hover:border-indigo-500/40 hover:bg-slate-800/40 shadow-none' 
          : 'border-slate-200 hover:border-indigo-300 hover:bg-white shadow-md'
      }`}
    >
      <div className="h-64 bg-slate-800 overflow-hidden relative">
        <img 
          src={project.imageUrl} 
          alt={project.title} 
          className="w-full h-full object-cover opacity-70 group-hover:opacity-100 group-hover:scale-110 transition-transform duration-700" 
        />
        <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-transparent to-transparent"></div>
      </div>
      <div className="p-10 flex-1 flex flex-col">
        <div className="flex gap-2 mb-6 flex-wrap">
          {project.tags.map(tag => (
            <span key={tag} className="text-[10px] font-black uppercase tracking-widest px-3 py-1.5 rounded-lg bg-indigo-500/10 text-indigo-400 border border-indigo-500/20">
              {tag}
            </span>
          ))}
        </div>
        <h4 className={`text-3xl font-bold mb-4 transition-colors ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>{project.title}</h4>
        <p className={`text-base leading-relaxed mb-8 flex-1 transition-colors ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>
          {project.description}
        </p>
        <div className="flex items-center gap-4">
          <Link 
            to={`/projects/${project.id}`}
            className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-3 rounded-xl transition-all flex items-center gap-2 text-sm font-bold shadow-lg shadow-indigo-600/20 active:scale-95"
          >
            View Case Study <ChevronRight size={18} />
