          <button className={`p-3 rounded-xl border transition-colors ${isDarkMode ? 'border-white/10 hover:bg-white/5 text-slate-400' : 'border-slate-200 hover:bg-slate-50 text-slate-600'}`}>
            <Github size={20} />
          </button>
        </div>
      </div>
    </div>
  );
};

